    64→  value: string | number;
    65→  label: string;
    66→}
    67→
    68→export interface PointsExtractData {
    69→  transactions: PointsTransaction[];
    70→  expiringPoints: ExpiringPoints[];
    71→  transactionsFilters: {
    72→    periods: FilterOption[];
    73→    types: FilterOption[];
    74→  };
    75→  expiringFilters: {
    76→    periods: FilterOption[];
    77→  };
    78→}
    79→
    80→
    81→export interface InitialState {
    82→  points?: number;
    83→  isLoadingBalance: boolean;
    84→  isErrorBalance: boolean;
    85→
    86→  products: PointsProduct[];
    87→  isLoadingProducts: boolean;
    88→  isErrorProducts: boolean;
    89→
    90→  isLoadingExtract: boolean;
    91→  isErrorExtract: boolean;
    92→
    93→  isLoadingStatement: boolean;
    94→  isErrorStatement: boolean;
    95→  data: any[];
    96→  isLoadingRescue: boolean;
    97→  isErrorRescue: boolean;
    98→  parameterization?: ParametrizationData[];
    99→  pointsQuantity: number;
   100→  isLoadingParameterization?: boolean;
   101→  isErrorParameterization?: boolean;
   102→  convertionFactor: number;
   103→  conversionFactor: number;
   104→}
   105→
   106→export type State = InitialState;
   107→
   108→export const initialState: InitialState = {
   109→  points: 0,
   110→  isLoadingBalance: true,
   111→  isErrorBalance: false,
   112→
   113→  products: [],
   114→  isLoadingProducts: true,
   115→  isErrorProducts: false,
   116→
   117→  isLoadingExtract: false,
   118→  isErrorExtract: false,
   119→
   120→  isLoadingStatement: false,
